#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        long long *freq = (long long *)calloc(K, sizeof(long long));
        if (!freq) return 0;
        freq[0] = 1; // empty prefix
        long long prefix = 0, ans = 0;
        for (int i = 0; i < N; ++i) {
            long long x;
            scanf("%lld", &x);
            prefix = (prefix + x) % K;
            if (prefix < 0) prefix += K;
            ans += freq[prefix];
            ++freq[prefix];
        }
        printf("%lld\n", ans);
        free(freq);
    }
    return 0;
}

